using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed "$type" (was "Discriminator").
            // Existing 500K documents and raw SQL queries use "Discriminator", so preserve it.
            b.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 — Cosmos `id` no longer includes the discriminator prefix.
            //   EF Core 8 wrote:  id = "Product|123"
            //   EF Core 9 writes: id = "123"
            // Existing documents still carry the old format.  The generator below keeps
            // new inserts consistent with them.
            // NOTE: FindAsync(key) internally builds the id from the key alone in EF 9,
            // so point-reads against legacy documents will miss.  Use LINQ queries instead,
            // or read by partition-key + id with the Cosmos SDK directly.
            b.Property<string>("__id")
             .HasValueGenerator<LegacyCosmosIdGenerator>();

            // BREAKING CHANGE 3 — HasIndex() now throws for the Cosmos provider.
            // Configure indexing policy in the Azure portal or via IaC instead.
            // Removed: b.HasIndex(p => p.Sku);
        });
    }
}

/// <summary>
/// Reproduces the EF Core 8 Cosmos id format: "{DiscriminatorValue}|{PrimaryKeyValue}".
/// Attach to the __id shadow property so new documents match the 500K existing ones.
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override string Next(EntityEntry entry)
        => $"{entry.Metadata.GetDiscriminatorValue()}|{entry.Property("Id").CurrentValue}";

    public override bool GeneratesTemporaryValues => false;
}

